# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request
import requests
import pandas as pd
from sklearn.model_selection import train_test_split
from collections import Counter
from sklearn.ensemble import RandomForestClassifier
from PIL import Image
import io
import numpy as np

app = Flask(__name__)
annotators = []  # to store annotators' REST API endpoints
labels_dict = {}  # to store labels received from each annotator
majority_votes = None
image_data = []
labels = []

@app.route('/register', methods=['POST'])
def register():
    """Register a new annotator"""
    global annotators
    data = request.get_json()
    if 'endpoint' in data:
        annotators.append(data['endpoint'])  # add the endpoint of the new annotator to the list
        return {'message': 'Annotator registered successfully'}, 201
    else:
        return {'error': 'Missing endpoint in request.'}, 400

@app.route('/label', methods=['POST'])
def label():
    """Accept labels from annotators"""
    global labels_dict, majority_votes
    data = request.get_json()
    if 'image' not in data or 'annotation' not in data:
        return {'error': 'Missing image and annotation in request.'}, 400
    image_id = data['image']
    label = data['annotation']
    if image_id not in labels_dict:
        labels_dict[image_id] = [label]
    else:
        labels_dict[image_id].append(label)
    
    majority_votes = get_majority_vote()  # update majority votes

    return {'message': 'Label received successfully'}, 201

def get_majority_vote():
    """Get the labels with a majority vote"""
    counts = Counter(label for image in labels_dict.values() for label in image)
    return counts.most_common(1)[0][0]

@app.route('/train', methods=['POST'])
def train():
    """Train the model with labeled data"""
    global majority_votes, image_data, labels
    
    if not majority_votes:
        return {'error': 'No labeled data available.'}, 400
        
    for image_id, label in majority_votes.items():
        response = requests.get(f'http://{image_id}')  # fetch the actual image using its id
        img = Image.open(io.BytesIO(response.content))
        image_data.append(np.array(img).flatten())  # Flatten the image data for training
        labels.append(label)
    
    X_train, _, y_train, _ = train_test_split(image_data, labels, test_size=0.2, random_state=42)
    
    clf = RandomForestClassifier()  # initialize the classifier
    clf.fit(X_train, y_train)  # train the model without validation to get results as quickly as possible
    
    return {'message': 'Model trained successfully'}, 201

if __name__ == "__main__":
    app.run(port=5000)